func TestEnumSnapshotResponseDtoType(t *testing.T) {
	t.Run("NewFromString_DataDisk", func(t *testing.T) {
		t.Parallel()
		val, err := NewSnapshotResponseDtoTypeFromString("DataDisk")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, SnapshotResponseDtoType("DataDisk"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_RootDisk", func(t *testing.T) {
		t.Parallel()
		val, err := NewSnapshotResponseDtoTypeFromString("RootDisk")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, SnapshotResponseDtoType("RootDisk"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewSnapshotResponseDtoTypeFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewSnapshotResponseDtoTypeFromString("DataDisk")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

